def validate(args, output):
    from collections import Counter
    candidates, target = args[0], args[1]
    avail = Counter(candidates)
    items = sorted(avail.items())
    correct = set()
    def bt(i, remaining, cur):
        if remaining == 0:
            correct.add(tuple(cur)); return
        if i >= len(items) or remaining < 0:
            return
        val, cnt = items[i]
        k = 0
        while k <= cnt and val * k <= remaining:
            bt(i + 1, remaining - val * k, cur + [val] * k)
            k += 1
    bt(0, target, [])
    seen = set()
    for combo in output:
        if not isinstance(combo, list):
            return False
        if sum(combo) != target:
            return False
        c = Counter(combo)
        for v, k in c.items():
            if avail.get(v, 0) < k:
                return False
        key = tuple(sorted(combo))
        if key in seen:
            return False
        seen.add(key)
    return seen == correct

