function validate(args, output) {
    const candidates = args[0], target = args[1];
    const avail = {};
    for (const x of candidates) avail[x] = (avail[x] || 0) + 1;
    const items = Object.keys(avail).map(Number).sort((a, b) => a - b).map(v => [v, avail[v]]);
    const correct = new Set();
    function bt(i, remaining, cur) {
        if (remaining === 0) { correct.add(cur.slice().sort((a, b) => a - b).join(',')); return; }
        if (i >= items.length || remaining < 0) return;
        const val = items[i][0], cnt = items[i][1];
        let k = 0;
        while (k <= cnt && val * k <= remaining) {
            bt(i + 1, remaining - val * k, cur.concat(Array(k).fill(val)));
            k++;
        }
    }
    bt(0, target, []);
    const seen = new Set();
    for (const combo of output) {
        if (!Array.isArray(combo)) return false;
        if (combo.reduce((a, b) => a + b, 0) !== target) return false;
        const c = {};
        for (const v of combo) c[v] = (c[v] || 0) + 1;
        for (const v in c) if ((avail[v] || 0) < c[v]) return false;
        const key = combo.slice().sort((a, b) => a - b).join(',');
        if (seen.has(key)) return false;
        seen.add(key);
    }
    if (seen.size !== correct.size) return false;
    for (const k of seen) if (!correct.has(k)) return false;
    return true;
}

