class Solution:
    def combinationSum2(self, candidates, target):
        from itertools import combinations
        cand = sorted(candidates)
        seen = set()
        for r in range(1, len(cand) + 1):
            for combo in combinations(cand, r):
                if sum(combo) == target:
                    seen.add(combo)
        res = [list(c) for c in seen]
        res.sort()
        return res

